// Theme switcher IIFE
(function(){
    var SUN = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>';
    var MOON = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z"/></svg>';
    
    function getPreferred() {
        var s = localStorage.getItem('gb-theme');
        if (s) return s;
        return window.matchMedia('(prefers-color-scheme:light)').matches ? 'light' : 'dark';
    }
    
    function set(t) {
        document.documentElement.setAttribute('data-theme', t);
        localStorage.setItem('gb-theme', t);
        updateBtn(t);
    }
    
    function updateBtn(t) {
        var btn = document.getElementById('theme-toggle');
        if (!btn) return;
        btn.innerHTML = t === 'dark' ? SUN : MOON;
        btn.setAttribute('aria-label', t === 'dark' ? 'Switch to light mode' : 'Switch to dark mode');
    }
    
    function toggle() {
        var cur = document.documentElement.getAttribute('data-theme') || 'dark';
        var next = cur === 'dark' ? 'light' : 'dark';
        document.documentElement.classList.add('theme-transitioning');
        set(next);
        setTimeout(function(){
            document.documentElement.classList.remove('theme-transitioning');
        }, 500);
    }
    
    set(getPreferred());
    window.__toggleTheme = toggle;
    window.__setTheme = set;
    window.__updateThemeBtn = function() {
        updateBtn(document.documentElement.getAttribute('data-theme') || 'dark');
    };
    
    document.addEventListener('click', function(e) {
        if (e.target.closest('#theme-toggle')) toggle();
    });
    
    document.addEventListener('htmx:afterSettle', function() {
        window.__updateThemeBtn();
    });
})();

// i18n IIFE
(function(){
    var currentLang = 'en';
    var translations = {};
    var supportedLangs = ['en', 'pt', 'es', 'fr', 'de', 'ja', 'zh-cn'];
    
    function loadCached(lang) {
        try {
            var cached = localStorage.getItem('gb_translations_' + lang + '_v2');
            if (cached) {
                translations = JSON.parse(cached);
                currentLang = lang;
                applyTranslations();
                return true;
            }
        } catch(e) {}
        return false;
    }
    
    function saveCache(lang, data) {
        try {
            localStorage.setItem('gb_translations_' + lang + '_v2', JSON.stringify(data));
        } catch(e) {}
    }
    
    function detectLang() {
        var path = window.location.pathname.toLowerCase();
        var parts = path.split('/');
        if (parts.length > 1 && supportedLangs.indexOf(parts[1]) !== -1) return parts[1];
        
        var cookie = document.cookie.match(/gb_lang=([^;]+)/);
        if (cookie) return cookie[1];
        
        var browser = (navigator.language || navigator.userLanguage || 'en').substring(0, 2);
        if (browser === 'zh') browser = 'zh-cn';
        if (supportedLangs.indexOf(browser) !== -1) return browser;
        
        return 'en';
    }
    
    function getLangPrefix() {
        var path = window.location.pathname.toLowerCase();
        var parts = path.split('/');
        if (parts.length > 1 && supportedLangs.indexOf(parts[1]) !== -1) return '/' + parts[1];
        return '';
    }
    
    function localizeLinks() {
        var prefix = getLangPrefix();
        if (!prefix || prefix === '/en') return;
        
        var links = document.querySelectorAll('a[href]');
        for (var i = 0; i < links.length; i++) {
            var link = links[i];
            var href = link.getAttribute('href');
            if (!href || href.match(/^(https?:)?\/\//) || href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('tel:')) {
                // Skip external, anchor, and protocol links
            } else if (href.startsWith('/') && !href.startsWith(prefix + '/')) {
                link.setAttribute('href', prefix + href);
            } else if (!href.startsWith('/')) {
                link.setAttribute('href', prefix + '/' + href);
            }
        }
    }
    
    function loadLang(lang, callback) {
        var xhr = new XMLHttpRequest();
        xhr.open('GET', '/lang/' + lang + '.json?v=' + (+new Date()), true);
        xhr.onload = function() {
            if (xhr.status === 200) {
                try {
                    translations = JSON.parse(xhr.responseText);
                    currentLang = lang;
                    saveCache(lang, translations);
                    document.cookie = 'gb_lang=' + lang + ';path=/;max-age=31536000';
                    applyTranslations();
                    if (document.getElementById('lang-flags')) injectFlags();
                    injectLangSelect();
                    if (callback) callback();
                } catch(e) {
                    console.warn('i18n:parse fail ' + lang, e);
                    if (lang !== 'en') loadLang('en', callback);
                }
            } else {
                if (lang !== 'en') loadLang('en', callback);
            }
        };
        xhr.onerror = function() {
            if (lang !== 'en') loadLang('en', callback);
        };
        xhr.send();
    }
    
    function loadBlogTranslation(slug, lang) {
        var xhr = new XMLHttpRequest();
        xhr.open('GET', '/lang/blog/' + slug + '/' + lang + '.json?v=' + (+new Date()), true);
        xhr.onload = function() {
            if (xhr.status === 200) {
                try {
                    var data = JSON.parse(xhr.responseText);
                    
                    var titleEl = document.querySelector('[data-blog-title]');
                    if (titleEl && data.title) titleEl.textContent = data.title;
                    
                    var subtitleEl = document.querySelector('[data-blog-subtitle]');
                    if (subtitleEl && data.subtitle) subtitleEl.textContent = data.subtitle;
                    
                    var dateEl = document.querySelector('[data-blog-date]');
                    if (dateEl && data.date) dateEl.textContent = data.date;
                    
                    var badgeEl = document.querySelector('[data-blog-badge]');
                    if (badgeEl && data.badge) badgeEl.textContent = data.badge;
                    
                    var attrEl = document.querySelector('[data-blog-attribution]');
                    if (attrEl) {
                        if (data.originally_published) {
                            attrEl.innerHTML = data.originally_published;
                            attrEl.style.display = '';
                        } else {
                            attrEl.style.display = 'none';
                        }
                    }
                    
                    var bodyEl = document.querySelector('[data-blog-body]');
                    if (bodyEl && data.body) {
                        bodyEl.innerHTML = data.body;
                    }
                    
                    // CTA section heading
                    var ctaHeadingEl = document.querySelector('[data-blog-cta-heading]');
                    if (ctaHeadingEl && data.cta_heading) {
                        ctaHeadingEl.innerHTML = data.cta_heading;
                    }
                    
                    // CTA section paragraphs (by position)
                    var ctaTextEls = document.querySelectorAll('[data-blog-cta-text]');
                    if (ctaTextEls && data.cta_text) {
                        for (var ci = 0; ci < ctaTextEls.length && ci < data.cta_text.length; ci++) {
                            ctaTextEls[ci].innerHTML = data.cta_text[ci];
                        }
                    }
                    
                    // Related post descriptions (by position)
                    var relatedDescEls = document.querySelectorAll('[data-blog-related-desc]');
                    if (relatedDescEls && data.related_desc) {
                        for (var ri = 0; ri < relatedDescEls.length && ri < data.related_desc.length; ri++) {
                            relatedDescEls[ri].innerHTML = data.related_desc[ri];
                        }
                    }
                    
                    // Related post dates (by position)
                    var relatedDateEls = document.querySelectorAll('[data-blog-related-date]');
                    if (relatedDateEls && data.related_date) {
                        for (var di = 0; di < relatedDateEls.length && di < data.related_date.length; di++) {
                            relatedDateEls[di].textContent = data.related_date[di];
                        }
                    }
                    
                    // Update tab title and metadata
                    if (data.title) {
                        document.title = data.title + " | General Bots Blog";
                        var ogTitle = document.querySelector('meta[property="og:title"]');
                        if (ogTitle) ogTitle.setAttribute('content', data.title + " | General Bots Blog");
                    }
                    if (data.subtitle) {
                        var metaDesc = document.querySelector('meta[name="description"]');
                        if (metaDesc) metaDesc.setAttribute('content', data.subtitle);
                        var ogDesc = document.querySelector('meta[property="og:description"]');
                        if (ogDesc) ogDesc.setAttribute('content', data.subtitle);
                    }
                } catch(e) {
                    console.warn('Error parsing blog translation for ' + slug + '/' + lang, e);
                }
            }
        };
        xhr.send();
    }
    
    function applyTranslations() {
        if (!translations || Object.keys(translations).length === 0) return;
        
        var els = document.querySelectorAll('[data-i18n]');
        for (var i = 0; i < els.length; i++) {
            var key = els[i].getAttribute('data-i18n');
            var text = translations[key];
            if (text) {
                if (els[i].tagName === 'INPUT' || els[i].tagName === 'TEXTAREA') {
                    els[i].setAttribute('placeholder', text);
                } else if (els[i].tagName === 'IMG') {
                    els[i].setAttribute('alt', text);
                } else {
                    els[i].textContent = text;
                }
            }
        }
        
        // Custom: data-i18n-html support for tags that need innerHTML translation
        var htmlEls = document.querySelectorAll('[data-i18n-html]');
        for (var j = 0; j < htmlEls.length; j++) {
            var htmlKey = htmlEls[j].getAttribute('data-i18n-html');
            var htmlText = translations[htmlKey];
            if (htmlText) {
                htmlEls[j].innerHTML = htmlText;
            }
        }
        
        // Custom: blog post body and metadata JSON translation
        var blogBody = document.querySelector('[data-blog-body]');
        if (blogBody) {
            var slug = blogBody.getAttribute('data-blog-slug');
            var loadedLang = blogBody.getAttribute('data-loaded-lang');
            if (slug && loadedLang !== currentLang) {
                blogBody.setAttribute('data-loaded-lang', currentLang);
                loadBlogTranslation(slug, currentLang);
            }
        }
        
        document.documentElement.lang = currentLang;
        document.documentElement.classList.add('i18n-ready');
    }
    
    function switchLang(lang) {
        if (lang === currentLang) return;
        var path = window.location.pathname;
        var search = window.location.search || '';
        var hash = window.location.hash || '';
        var parts = path.split('/');
        while (parts.length > 1 && supportedLangs.indexOf(parts[1]) !== -1) {
            parts.splice(1, 1);
        }
        path = parts.join('/') || '/';
        document.cookie = 'gb_lang=' + lang + ';path=/;max-age=31536000';
        window.location.href = (lang === 'en' ? path : '/' + lang + path) + search + hash;
    }
    
    var flagLabels = {'en': 'EN', 'pt': 'PT', 'es': 'ES', 'fr': 'FR', 'de': 'DE', 'ja': 'JA', 'zh-cn': 'ZH'};
    
    function injectFlags() {
        var containers = document.querySelectorAll('.lang-flags');
        if (!containers.length) return;
        for (var ci = 0; ci < containers.length; ci++) {
            var container = containers[ci];
            container.innerHTML = '';
            for (var i = 0; i < supportedLangs.length; i++) {
                var lang = supportedLangs[i];
                var a = document.createElement('a');
                a.href = '#';
                a.title = lang;
                var isActive = lang === currentLang;
                a.className = 'lang-flag-btn';
                a.style.opacity = isActive ? '1' : '.45';
                a.onmouseover = function() { this.style.opacity = 1; };
                a.onmouseout = function() {
                    if (this.getAttribute('data-lang') !== currentLang) this.style.opacity = .45;
                };
                a.setAttribute('data-lang', lang);
                a.onclick = (function(l) {
                    return function(e) {
                        e.preventDefault();
                        switchLang(l);
                    };
                })(lang);
                a.textContent = flagLabels[lang] || lang.toUpperCase();
                container.appendChild(a);
            }
        }
    }
    
    function injectLangSelect() {
        var sel = document.getElementById('lang-select');
        if (!sel) return;
        sel.innerHTML = '';
        for (var i = 0; i < supportedLangs.length; i++) {
            var lang = supportedLangs[i];
            var opt = document.createElement('option');
            opt.value = lang;
            opt.textContent = flagLabels[lang] || lang.toUpperCase();
            if (lang === currentLang) opt.selected = true;
            sel.appendChild(opt);
        }
        sel.onchange = function() {
            switchLang(this.value);
        };
    }
    
    window.__switchLang = switchLang;
    window.__applyTranslations = applyTranslations;
    window.__injectFlags = injectFlags;
    window.__injectLangSelect = injectLangSelect;
    window.__localizeLinks = localizeLinks;
    window.__currentLang = function() { return currentLang; };
    
    var detectedLang = detectLang();
    if (!loadCached(detectedLang)) {
        loadLang(detectedLang, function() {
            setTimeout(localizeLinks, 100);
        });
    } else {
        localizeLinks();
        loadLang(detectedLang);
    }
    
    var _flagsInjected = false;
    (function retryInject() {
        if (_flagsInjected) return;
        var hasFlags = document.querySelector('.lang-flags');
        var hasSelect = document.getElementById('lang-select');
        if (hasFlags || hasSelect) {
            _flagsInjected = true;
            if (hasFlags) injectFlags();
            injectLangSelect();
            localizeLinks();
        } else {
            setTimeout(retryInject, 200);
        }
    })();
})();

function initHeader() {
    if (!window._hd) {
        window._hd = true;
        document.addEventListener("click", function(e) {
            var t = e.target.closest("#mobile-toggle");
            if (t) {
                var o = document.getElementById("mobile-overlay");
                if (o) o.classList.toggle("open");
                return;
            }
            var ov = document.getElementById("mobile-overlay");
            if (ov && ov.classList.contains("open")) {
                if (e.target.closest("#mobile-overlay a")) {
                    ov.classList.remove("open");
                } else if (e.target.closest("#mobile-overlay") && !e.target.closest(".mobile-overlay-inner")) {
                    ov.classList.remove("open");
                }
            }
        });
        window.addEventListener("scroll", function() {
            var header = document.querySelector(".site-header");
            if (!header) return;
            var should = window.scrollY > 60;
            header.classList.toggle("header-shrunk", should);
        }, {passive: true});
    }
    var header = document.querySelector(".site-header");
    if (header) {
        var shrunk = header.classList.contains("header-shrunk");
    }
}

function initReveal() {
    if (!('IntersectionObserver' in window)) {
        document.querySelectorAll('.reveal').forEach(function(el) {
            el.classList.add('visible');
        });
        return;
    }
    var observer = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
            if (entry.isIntersecting) {
                entry.target.classList.add('visible');
                observer.unobserve(entry.target);
            }
        });
    }, {threshold: 0.08, rootMargin: '0px 0px -40px 0px'});
    
    document.querySelectorAll('.reveal').forEach(function(el) {
        observer.observe(el);
    });
}

function initCounters() {
    if (!('IntersectionObserver' in window)) return;
    var counters = document.querySelectorAll('[data-count]');
    if (!counters.length) return;
    
    var observer = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
            if (entry.isIntersecting) {
                animateCounter(entry.target);
                observer.unobserve(entry.target);
            }
        });
    }, {threshold: 0.3});
    
    counters.forEach(function(el) {
        observer.observe(el);
    });
    
    function animateCounter(el) {
        var target = parseInt(el.getAttribute('data-count'), 10);
        var suffix = el.getAttribute('data-suffix') || '';
        var prefix = el.getAttribute('data-prefix') || '';
        var duration = 1200;
        var start = 0;
        var startTime = null;
        
        function step(ts) {
            if (!startTime) startTime = ts;
            var progress = Math.min((ts - startTime) / duration, 1);
            var eased = 1 - Math.pow(1 - progress, 3);
            var current = Math.floor(eased * target);
            el.textContent = prefix + current + suffix;
            if (progress < 1) requestAnimationFrame(step);
            else el.textContent = prefix + target + suffix;
        }
        requestAnimationFrame(step);
    }
}

function initThirdParty() {
    var gc = document.createElement('script');
    gc.async = true;
    gc.src = 'https://gc.zgo.at/count.js';
    gc.setAttribute('data-goatcounter', 'https://generalbots.org/count');
    document.body.appendChild(gc);
}

function initDropdowns() {
    if (window._dd) return;
    var triggers = document.querySelectorAll('.dropdown-trigger');
    if (!triggers.length) return;
    
    window._dd = true;
    document.addEventListener('click', function(e) {
        if (e.target.closest('#theme-toggle')) return;
        var isInsideTriggerOrMenu = false;
        document.querySelectorAll('.nav-dropdown-wrapper').forEach(function(wrapper) {
            if (wrapper.contains(e.target)) isInsideTriggerOrMenu = true;
        });
        
        if (!isInsideTriggerOrMenu) {
            document.querySelectorAll('.dropdown-menu').forEach(function(m) {
                m.classList.add('hidden');
                m.classList.remove('open');
                var tr = m.previousElementSibling;
                if (tr) {
                    tr.classList.remove('active');
                    tr.setAttribute('aria-expanded', 'false');
                }
            });
        }
    });
    
    triggers.forEach(function(trigger) {
        var menu = trigger.nextElementSibling;
        if (!menu || !menu.classList.contains('dropdown-menu')) return;
        
        trigger.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            var isClosed = menu.classList.contains('hidden');
            document.querySelectorAll('.dropdown-menu').forEach(function(m) {
                m.classList.add('hidden');
                m.classList.remove('open');
                var tr = m.previousElementSibling;
                if (tr) {
                    tr.classList.remove('active');
                    tr.setAttribute('aria-expanded', 'false');
                }
            });
            
            if (isClosed) {
                menu.classList.remove('hidden');
                menu.classList.add('open');
                trigger.classList.add('active');
                trigger.setAttribute('aria-expanded', 'true');
            } else {
                menu.classList.add('hidden');
                menu.classList.remove('open');
                trigger.classList.remove('active');
                trigger.setAttribute('aria-expanded', 'false');
            }
        });
    });
    
    var mobileTriggers = document.querySelectorAll('.mobile-dropdown-trigger');
    mobileTriggers.forEach(function(trigger) {
        var content = trigger.nextElementSibling;
        if (!content || !content.classList.contains('mobile-dropdown-content')) return;
        
        trigger.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            var isHidden = content.classList.contains('hidden');
            if (isHidden) {
                content.classList.remove('hidden');
                trigger.classList.add('active');
            } else {
                content.classList.add('hidden');
                trigger.classList.remove('active');
            }
        });
    });
}

document.addEventListener('DOMContentLoaded', function() {
    initHeader();
    initDropdowns();
    initReveal();
    initCounters();
    initThirdParty();
});

document.body.addEventListener('htmx:afterSwap', function(e) {
    if (e.detail && e.detail.requestConfig && e.detail.requestConfig.path && e.detail.requestConfig.path.indexOf('/partials/') !== -1) {
        initHeader();
        initDropdowns();
        var containers = document.querySelectorAll('.lang-flags');
        if (containers.length) {
            for (var ci = 0; ci < containers.length; ci++) {
                containers[ci].innerHTML = '';
            }
            if (window.__injectFlags) window.__injectFlags();
        }
        if (document.getElementById('lang-select') && window.__injectLangSelect) window.__injectLangSelect();
        if (window.__applyTranslations) window.__applyTranslations();
        if (window.__localizeLinks) window.__localizeLinks();
    }
    setTimeout(function() {
        if (window.__applyTranslations) window.__applyTranslations();
        initReveal();
        initCounters();
    }, 50);
});